module top_module(in, decoded_out);parameter N = 3;

    input  wire [N-1:0] in;
    output reg  [2**N-1:0] decoded_out;

    always @(*)
        begin
            decoded_out[0] = ~in[2] & ~in[1] & ~in[0];
            decoded_out[1] = ~in[2] & ~in[1] &  in[0];
            decoded_out[2] = ~in[2] &  in[1] & ~in[0];
            decoded_out[3] = ~in[2] &  in[1] &  in[0];
            decoded_out[4] =  in[2] & ~in[1] & ~in[0];
            decoded_out[5] =  in[2] & ~in[1] &  in[0];
            decoded_out[6] =  in[2] &  in[1] & ~in[0];
            decoded_out[7] =  in[2] &  in[1] &  in[0];
        end 

endmodule
